from shiny import App, ui, render, reactive
from pathlib import Path
from pyodide.http import open_url
import pandas as pd
import numpy as np
import random

# Load CSV once at startup
df = pd.read_csv(open_url('https://raw.githubusercontent.com/bbpi2/shp-where-to-eat/refs/heads/main/data/restaurants.csv'))
cuisines = df['cuisine'].unique().tolist()
closing_times = ["early", "9:00", "9:30", "10:00", "late"]

app_ui = ui.page_fillable(
      ui.card(
        ui.card_header("Pick a cuisine"),
        ui.card_body(
          ui.input_checkbox_group("selected_cuisines", "", cuisines, selected=cuisines)
        ),
        fill=False
      ),
      ui.card(
        ui.input_action_button("go", "Pick a Restaurant"),
        fill=False
      ),
      # ui.input_action_button("go", "Pick a Restaurant"),
      ui.output_text_verbatim("result")
)

def server(input, output, session):
    @reactive.Calc
    @reactive.event(input.go)
    def pick_restaurant():
        cuisine_filter = input.selected_cuisines()
        df_selected = df.query('cuisine in @cuisine_filter')
        idx = random.randrange(len(df_selected))
        row = df_selected.iloc[idx]
        return row.to_string()

    @output
    @render.text
    def result():
        return pick_restaurant()

    @output
    @render.text
    def result():
        return pick_restaurant()

app = App(app_ui, server)
